import React from 'react'

const Home = () => {
    return (
        <>
            <div className='main-heading'>
                welcome to your world-where it gets the attention it quietly deserves.
            </div>
            <div className='main-menu'>
                <div className='menu-box'>
                    Journal
                </div>
                <div className='menu-box'>
                    Mood
                </div>
                <div className='menu-box'>
                    Tasks
                </div>
                <div className='menu-box'>
                    DashBoard
                </div>
            </div>
            <div className='design-layout'>
                <img src='./leaf.png'></img>
            </div>
            <div className='footer-heading'>
                DearDiary - Divya
            </div>
            <Stylesheet/>
        </>
    )
}

const Stylesheet = () => {
    return <style>{`
        .main-menu{
            display:flex;
            flex-direction:row;
            gap:2%;
            height:200px;
            width:100%;
            align-items:center;
            justify-content:center;
            position:absolute;
            bottom:40%;
            // background-color:var(--secondary-color);
        }
        .menu-box{
            background-color:var(--secondary-color);
            width:150px;
            height:80%;
            display:flex;
            align-items:center;
            justify-content:center;
            border-radius:10px;
        }
        .menu-box:hover {
            transform:scale(1.05);
             box-shadow: 0 4px 20px rgba(0, 0, 0, 0.15);
        }
        .footer-heading{
            position:absolute;
            bottom:10%;
            right:30%;
            font-size:30px;
        }
        .design-layout{
           
        }
    `}</style>
}

export default Home
